mapper.select:
SELECT p.le, p.project_no, p.parent_project_no, p.project_name, p.project_desc, p.project_code, p.project_home, p.status, p.public_yn, p.start_date, p.end_date, FN_GET_CODE_NAME(p.status) AS project_status, j.title AS latest_job_title FROM vw_project p LEFT JOIN users u ON p.user_id = u.user_id LEFT JOIN ( SELECT project_no, title FROM (SELECT project_no, title, ROW_NUMBER() OVER (PARTITION BY project_no ORDER BY add_date DESC) as rn FROM job) WHERE rn = 1 ) j ON j.project_no = p.project_no
AND p.project_name LIKE '%' || #{search.projectName} || '%'
AND p.status = #{search.projectStatus}
AND u.username LIKE '%' || #{search.projectAssignee} || '%'
AND p.start_date >= #{search.startDate}
AND p.end_date <= #{search.endDate}
AND ( p.status != 390 OR (p.status = 390 AND EXISTS ( SELECT 1 FROM g_project gp JOIN members m ON gp.group_no = m.group_no WHERE gp.project_no = p.project_no AND m.user_id = #{currentUserId} AND gp.pm = 1 )) ) AND ( EXISTS (SELECT 1 FROM vw_member WHERE project_no = p.project_no AND user_id = #{currentUserId}) OR p.public_yn = 1 )

insert.if:
MERGE INTO g_project gp USING (
SELECT #{groupNo} AS group_no FROM DUAL
) m ON (gp.project_no = #{projectNo} AND gp.group_no = m.group_no) WHEN MATCHED THEN UPDATE SET gp.pm = 1 WHEN NOT MATCHED THEN INSERT (project_no, group_no, pm) VALUES (#{projectNo}, m.group_no, 1)
